// build.rs — compile the custom Q8_0 dequant-GEMV CUDA kernel to PTX at BUILD
// TIME (nvcc is present only in the `nvidia/cuda:*-devel` build stage; the
// `node:22-slim` runtime stage has neither nvcc nor libnvrtc). The PTX string is
// embedded in the binary via `include_str!(OUT_DIR/q8_gemv.ptx)` and loaded at
// runtime through the cudarc DRIVER (cuModuleLoadData) — no runtime NVRTC.
//
// Discipline:
//   * Only act when the `cuda` cargo feature is on (CARGO_FEATURE_CUDA set).
//     Otherwise no-op so `cargo check` (no features) is unaffected.
//   * If nvcc is absent or fails, print a `cargo:warning=` and DO NOT fail the
//     build: write an EMPTY ptx file (so include_str! always resolves) and do
//     NOT emit the `q8_kernel_ptx` cfg. The runtime then treats the kernel as
//     unavailable and the MESH_GPU_Q8K flag silently no-ops to the existing
//     cuBLAS/CPU path.
//   * Re-run on kernel change.

use std::env;
use std::path::Path;
use std::process::Command;

fn main() {
    // Always make these cfg names known to the compiler so `#[cfg(..._cubin)]`
    // does not warn under `check-cfg` even on the no-cuda / nvcc-absent path.
    println!("cargo:rustc-check-cfg=cfg(q8_kernel_cubin)");
    println!("cargo:rustc-check-cfg=cfg(q4k_kernel_cubin)");
    println!("cargo:rustc-check-cfg=cfg(q6k_kernel_cubin)");
    println!("cargo:rustc-check-cfg=cfg(prefill_attn_kernel_cubin)");
    println!("cargo:rustc-check-cfg=cfg(mamba_scan_kernel_cubin)");
    println!("cargo:rustc-check-cfg=cfg(mamba2_ssd_scan_kernel_cubin)");
    println!("cargo:rustc-check-cfg=cfg(mamba2_gated_norm_kernel_cubin)");

    let out_dir = env::var("OUT_DIR").expect("OUT_DIR not set by cargo");

    println!("cargo:rerun-if-changed=build.rs");

    // Each kernel: (source .cu, output cubin name, rustc-cfg flag, env-flag label
    // used only for the human-readable cargo:warning). Compiled identically:
    // `nvcc --cubin -arch=sm_89` → native SASS (no PTX) so the L4 driver loads it
    // directly via cuModuleLoadData with no PTX-version JIT check.
    //
    // Discipline (per kernel, matching the original q8 path):
    //   * Only compile under the `cuda` feature; otherwise write an EMPTY cubin so
    //     the Rust `include_bytes!` fallback always resolves and the runtime
    //     treats the kernel as unavailable (the env flag silently no-ops).
    //   * If nvcc is absent or fails, print a `cargo:warning=`, write an EMPTY
    //     cubin, and DO NOT emit the cfg — the kernel is then unavailable.
    let kernels: &[(&str, &str, &str, &str)] = &[
        ("src/cuda/q8_gemv.cu", "q8_gemv.cubin", "q8_kernel_cubin", "MESH_GPU_Q8K"),
        ("src/cuda/q4k_gemv.cu", "q4k_gemv.cubin", "q4k_kernel_cubin", "MESH_GPU_Q4K"),
        ("src/cuda/q6k_gemv.cu", "q6k_gemv.cubin", "q6k_kernel_cubin", "MESH_GPU_Q4K"),
        ("src/cuda/prefill_attn.cu", "prefill_attn.cubin", "prefill_attn_kernel_cubin", "MESH_GPU_PREFILL_ATTN"),
        ("src/cuda/mamba_scan.cu", "mamba_scan.cubin", "mamba_scan_kernel_cubin", "MESH_GPU_SCAN"),
        ("src/cuda/mamba2_ssd_scan.cu", "mamba2_ssd_scan.cubin", "mamba2_ssd_scan_kernel_cubin", "MESH_GPU_SCAN"),
        ("src/cuda/mamba2_gated_norm.cu", "mamba2_gated_norm.cubin", "mamba2_gated_norm_kernel_cubin", "MESH_GPU_SSM_FUSED"),
    ];

    let cuda = env::var("CARGO_FEATURE_CUDA").is_ok();

    // Target SM architecture for the emitted cubins. Prod (Cloud Run L4 = Ada)
    // is sm_89 and stays the default. A local CUDA dev box with a different GPU
    // (e.g. GTX 1080 Ti = Pascal = sm_61) overrides via `MESH_CUDA_ARCH=sm_61`
    // so the cubins are NATIVE SASS the local driver can `cuModuleLoadData` —
    // required to exercise the GPU parity gate locally before a blind cloud
    // build. `--cubin -arch=<sm_xx>` emits single-arch SASS (no PTX, no JIT).
    let arch = env::var("MESH_CUDA_ARCH").unwrap_or_else(|_| "sm_89".to_string());
    println!("cargo:rerun-if-env-changed=MESH_CUDA_ARCH");

    for &(cu_src, cubin_name, cfg, flag) in kernels {
        let cubin_path = Path::new(&out_dir).join(cubin_name);

        if !cuda {
            // No-op for non-cuda builds, but still write an empty cubin so the Rust
            // `include_bytes!` fallback always resolves regardless of feature flags.
            let _ = std::fs::write(&cubin_path, []);
            continue;
        }

        println!("cargo:rerun-if-changed={cu_src}");

        // `--cubin -arch=<arch>` emits native SASS (no PTX). arch from
        // MESH_CUDA_ARCH (default sm_89 = L4/Ada; sm_61 = local 1080 Ti).
        let status = Command::new("nvcc")
            .args([
                "--cubin",
                cu_src,
                "-o",
                cubin_path.to_str().unwrap(),
                &format!("-arch={arch}"),
                // Pre-Turing arches (e.g. sm_61 local dev box) warn as deprecated;
                // suppress so the warning never trips a strict log scan. No-op on
                // sm_89 (Turing+). Does NOT affect emitted SASS.
                "-Wno-deprecated-gpu-targets",
            ])
            .status();

        match status {
            Ok(s) if s.success() => {
                // Cubin compiled successfully — signal the runtime to enable it.
                println!("cargo:rustc-cfg={cfg}");
                println!("cargo:warning={cu_src} compiled to CUBIN ({arch}) — {flag} kernel available");
            }
            Ok(s) => {
                println!(
                    "cargo:warning=nvcc failed (exit {s}) compiling {cu_src} — {flag} kernel DISABLED, falling back to cuBLAS/CPU"
                );
                let _ = std::fs::write(&cubin_path, []);
            }
            Err(e) => {
                println!(
                    "cargo:warning=nvcc not found ({e}) — {flag} kernel DISABLED, falling back to cuBLAS/CPU"
                );
                let _ = std::fs::write(&cubin_path, []);
            }
        }
    }
}
